import React, { useState, useCallback, useMemo, useEffect } from 'react';

const Wallet = () => {
  const [walletAddress, setWalletAddress] = useState('');
  const [balance, setBalance] = useState(0);
  const [transactionHistory, setTransactionHistory] = useState([]);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [amountToAdd, setAmountToAdd] = useState('');
  const [isConnecting, setIsConnecting] = useState(false);
  const [isMetaMaskInstalled, setIsMetaMaskInstalled] = useState(false);
  const [networkStatus, setNetworkStatus] = useState('');

  // Sample transaction history (in a real app, this would come from backend)
  const sampleTransactions = useMemo(() => [
    {
      id: 1,
      type: 'deposit',
      amount: 100,
      timestamp: '2023-05-15T10:30:00Z',
      description: 'Initial deposit'
    },
    {
      id: 2,
      type: 'earning',
      amount: 25.50,
      timestamp: '2023-05-16T14:22:00Z',
      description: 'Crypto hunter bounty completed'
    },
    {
      id: 3,
      type: 'earning',
      amount: 15.75,
      timestamp: '2023-05-17T09:15:00Z',
      description: 'Freelance task completed'
    },
    {
      id: 4,
      type: 'withdrawal',
      amount: -50,
      timestamp: '2023-05-18T16:45:00Z',
      description: 'Withdrawal to external wallet'
    },
  ], []);

  // Check if MetaMask is installed and initialize
  useEffect(() => {
    const checkMetaMask = async () => {
      if (window.ethereum) {
        setIsMetaMaskInstalled(true);
        try {
          // Check if accounts are already connected
          const accounts = await window.ethereum.request({ method: 'eth_accounts' });
          if (accounts.length > 0) {
            setWalletAddress(accounts[0]);
            // Get network info
            const chainId = await window.ethereum.request({ method: 'eth_chainId' });
            setNetworkStatus(parseInt(chainId, 16) === 1 ? 'Ethereum Mainnet' : 'Test Network');
          }
        } catch (error) {
          console.error('Error checking MetaMask accounts:', error);
        }
      } else {
        setIsMetaMaskInstalled(false);
      }
    };

    checkMetaMask();

    // Listen for account changes
    if (window.ethereum) {
      window.ethereum.on('accountsChanged', handleAccountsChanged);
      window.ethereum.on('chainChanged', handleChainChanged);
      return () => {
        if (window.ethereum) {
          window.ethereum.removeListener('accountsChanged', handleAccountsChanged);
          window.ethereum.removeListener('chainChanged', handleChainChanged);
        }
      };
    }
  }, []);

  const handleAccountsChanged = async (accounts) => {
    if (accounts.length > 0) {
      setWalletAddress(accounts[0]);
    } else {
      setWalletAddress('');
    }
  };

  const handleChainChanged = async (chainId) => {
    setNetworkStatus(parseInt(chainId, 16) === 1 ? 'Ethereum Mainnet' : 'Test Network');
  };

  // Initialize wallet on mount
  useEffect(() => {
    // Load any existing transaction history from localStorage or backend
    const loadWallet = async () => {
      try {
        // In a real app, this would fetch from backend
        // For demo, we'll use sample data
        setTransactionHistory(sampleTransactions);
      } catch (error) {
        console.error('Failed to load wallet:', error);
        // Fallback to sample data
        setTransactionHistory(sampleTransactions);
      }
    };

    loadWallet();
  }, []);

  const handleConnectWallet = useCallback(async () => {
    if (!window.ethereum) {
      alert('MetaMask is not installed. Please install MetaMask to use this feature.');
      return;
    }

    setIsConnecting(true);
    try {
      // Request account access
      const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
      if (accounts.length > 0) {
        setWalletAddress(accounts[0]);

        // Get network info
        const chainId = await window.ethereum.request({ method: 'eth_chainId' });
        setNetworkStatus(parseInt(chainId, 16) === 1 ? 'Ethereum Mainnet' : 'Test Network');
      }
    } catch (error) {
      console.error('Failed to connect to MetaMask:', error);
      alert('Failed to connect to MetaMask. Please try again.');
    } finally {
      setIsConnecting(false);
    }
  }, []);

  const handleGenerateWallet = useCallback(() => {
    // Fallback to mock wallet if MetaMask is not available
    if (!window.ethereum) {
      const mockAddress = '0x' + Math.random().toString(16).substr(2, 40);
      setWalletAddress(mockAddress);
      setBalance(0);
      setTransactionHistory([]);
      return;
    }

    // If MetaMask is available, connect to it
    handleConnectWallet();
  }, [handleConnectWallet]);

  const handleAddFunds = useCallback(async () => {
    if (!amountToAdd || parseFloat(amountToAdd) <= 0) {
      alert('Please enter a valid amount');
      return;
    }

    setIsAddingFunds(true);
    try {
      // In a real app, this would make an API call to add funds
      // For demo, we'll simulate the transaction
      const amount = parseFloat(amountToAdd);
      setBalance(prevBalance => prevBalance + amount);

      // Add to transaction history
      const newTransaction = {
        id: Date.now(),
        type: 'deposit',
        amount: amount,
        timestamp: new Date().toISOString(),
        description: 'Manual deposit'
      };

      setTransactionHistory(prev => [newTransaction, ...prev]);
      setAmountToAdd('');
    } catch (error) {
      console.error('Failed to add funds:', error);
      alert('Failed to add funds. Please try again.');
    } finally {
      setIsAddingFunds(false);
    }
  }, [amountToAdd]);

  const handleWithdraw = useCallback(async (amount) => {
    if (balance < amount) {
      alert('Insufficient funds');
      return;
    }

    try {
      // In a real app, this would make an API call to withdraw funds
      setBalance(prevBalance => prevBalance - amount);

      // Add to transaction history
      const newTransaction = {
        id: Date.now(),
        type: 'withdrawal',
        amount: -amount,
        timestamp: new Date().toISOString(),
        description: 'Withdrawal'
      };

      setTransactionHistory(prev => [newTransaction, ...prev]);
    } catch (error) {
      console.error('Failed to withdraw:', error);
      alert('Failed to withdraw. Please try again.');
    }
  }, [balance]);

  // Memoize transaction history display for performance
  const transactionItems = useMemo(() => {
    return transactionHistory.length > 0 ? (
      transactionHistory.map(tx => (
        <div key={tx.id} className={`transaction-item ${tx.type}`}>
          <div className="transaction-info">
            <span className="transaction-type">
              {tx.type === 'deposit' ? 'Deposit' : tx.type === 'withdrawal' ? 'Withdrawal' : 'Earning'}
            </span>
            <span className="transaction-description">{tx.description}</span>
          </div>
          <div className="transaction-amount">
            {tx.type === 'deposit' ? `+$${tx.amount.toFixed(2)}` :
             tx.type === 'withdrawal' ? `-$${Math.abs(tx.amount).toFixed(2)}` :
             `$${tx.amount.toFixed(2)}`}
          </div>
          <div className="transaction-time">
            {new Date(tx.timestamp).toLocaleString()}
          </div>
        </div>
      ))
    ) : (
      <p className="empty-state">No transactions yet. Start earning with your agents to see transactions here.</p>
    );
  }, [transactionHistory]);

  // Futuristic gradient animations
  const gradientStyles = useMemo(() => ({
    primary: {
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    },
    secondary: {
      background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
    },
    success: {
      background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
    },
    warning: {
      background: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
    },
    glass: {
      background: 'rgba(255, 255, 255, 0.1)',
      backdropFilter: 'blur(10px)',
      border: '1px solid rgba(255, 255, 255, 0.2)',
    },
    card: {
      background: 'rgba(0, 0, 0, 0.2)',
      backdropFilter: 'blur(20px)',
      border: '1px solid rgba(255, 255, 255, 0.1)',
      boxShadow: '0 8px 32px 0 rgba(0, 0, 0, 0.37)',
    }
  }), []);

  if (!walletAddress && !isConnecting) {
    return (
      <div className="wallet-container">
        <div className={`${glassStyles.card} wallet-card`}>
          <h2>Connect Your Wallet</h2>
          <p>Securely connect your MetaMask wallet to start earning with our multi-agent system</p>
          {!isMetaMaskInstalled ? (
            <div className="metamask-notice">
              <h3>MetaMask Not Detected</h3>
              <p>Please install <a href="https://metamask.io/" target="_blank" rel="noreferrer">MetaMask</a> to use this feature</p>
              <button className="btn-outline" onClick={handleGenerateWallet}>
                Use Demo Wallet (Mock)
              </button>
            </div>
          ) : (
            <button
              className="btn-primary"
              onClick={handleConnectWallet}
              disabled={isConnecting}
            >
              {isConnecting ? 'Connecting...' : 'Connect MetaMask'}
            </button>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="wallet-container">
      <div className="wallet-header">
        <h2>My Wallet</h2>
        <div className="wallet-actions">
          <button className="btn-secondary" onClick={handleGenerateWallet}>
            {walletAddress ? 'Reset Wallet' : 'Create New Wallet'}
          </button>
        </div>
      </div>

      <div className={`${glassStyles.card} wallet-balance`}>
        <div className="balance-title">Wallet Balance</div>
        <div className="balance-amount">${balance.toFixed(2)}</div>
        <div className="wallet-address">
          <span>Address: {walletAddress}</span>
          {walletAddress && (
            <button className="btn-outline copy-address" onClick={() => {
              navigator.clipboard.writeText(walletAddress);
              alert('Address copied to clipboard!');
            }}>
              Copy
            </button>
          )}
        </div>
        {networkStatus && (
          <div className="network-status">
            Network: {networkStatus}
          </div>
        )}
      </div>

      <div className={`${glassStyles.card} wallet-section`}>
        <h3>Add Funds</h3>
        <form className="add-funds-form" onSubmit={(e) => {
          e.preventDefault();
          handleAddFunds();
        }}>
          <div className="form-group">
            <label htmlFor="amount">Amount ($)</label>
            <input
              type="number"
              id="amount"
              value={amountToAdd}
              onChange={(e) => setAmountToAdd(e.target.value)}
              placeholder="Enter amount to add"
              min="0.01"
              step="0.01"
              required
              disabled={isAddingFunds}
            />
          </div>
          <button
            type="submit"
            className="btn-primary"
            disabled={isAddingFunds || !amountToAdd || parseFloat(amountToAdd) <= 0}
          >
            {isAddingFunds ? 'Adding...' : 'Add Funds'}
          </button>
        </form>
      </div>

      <div className={`${glassStyles.card} wallet-section`}>
        <h3>Transaction History</h3>
        {transactionItems}
      </div>

      <div className={`${glassStyles.card} wallet-section`}>
        <h3>Quick Actions</h3>
        <div className="quick-actions">
          <button className="btn-outline" onClick={() => handleWithdraw(25)}>
            Withdraw $25
          </button>
          <button className="btn-outline" onClick={() => handleWithdraw(50)}>
            Withdraw $50
          </button>
          <button className="btn-outline" onClick={() => handleWithdraw(100)}>
            Withdraw $100
          </button>
        </div>
      </div>
    </div>
  );
};

export default Wallet;
